#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);long long dp[12]={0};dp[0]=1;for(int i=1;i<=n;i++){dp[i]=dp[i-1]+(i>=2?dp[i-2]:0)+(i>=3?dp[i-3]:0);}printf("%lld\n",dp[n]);}
